  ('locality-d592fc58-moex-00008', 'locality-d592fc58', 'locality-d592fc58-moex-114-d3ff7f6b', 'sub-locality-d592fc58-02', NULL, 'single_choice', '甲與乙都是咖啡的愛好者。甲每個月固定喝 30 杯咖啡，乙每個月固定花 1,000 元喝咖啡。甲乙 兩人的咖啡需求價格彈性各為何？', '["甲的咖啡需求價格彈性為0，乙的咖啡需求價格彈性為1", "甲的咖啡需求價格彈性為1，乙的咖啡需求價格彈性為0", "甲與乙的咖啡需求價格彈性均為0", "甲與乙的咖啡需求價格彈性均為1"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:24+00:00", "source_pdf_sha1": "6852e28c95cc", "answer_pdf_sha1": "5696f1cd2c60", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "318", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "商業行政"}'::jsonb, NULL),
  ('locality-d592fc58-moex-00009', 'locality-d592fc58', 'locality-d592fc58-moex-114-d3ff7f6b', 'sub-locality-d592fc58-02', NULL, 'single_choice', '假設其他條件不變，在兩期模型下，如利率上升造成第一期儲蓄減少，下列敘述何者正確？', '["對第一期的消費而言，利率上升的替代效果大於所得效果", "對第一期的消費而言，利率上升的替代效果小於所得效果", "對第一期的消費而言，利率上升的替代效果等於所得效果", "對第二期的消費而言，利率上升的替代效果等於所得效果"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:24+00:00", "source_pdf_sha1": "6852e28c95cc", "answer_pdf_sha1": "5696f1cd2c60", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "318", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "商業行政"}'::jsonb, NULL),
  ('locality-d592fc58-moex-00010', 'locality-d592fc58', 'locality-d592fc58-moex-114-d3ff7f6b', 'sub-locality-d592fc58-02', NULL, 'single_choice', '已知某一生產函數為Q=K0.5L0.5，其中Q代表產量，K代表資本，L代表勞動，則此生產函數的 規模報酬呈：', '["遞增", "遞減", "固定", "先增後減"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:24+00:00", "source_pdf_sha1": "6852e28c95cc", "answer_pdf_sha1": "5696f1cd2c60", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "318", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "商業行政"}'::jsonb, NULL),
  ('locality-d592fc58-moex-00011', 'locality-d592fc58', 'locality-d592fc58-moex-114-d3ff7f6b', 'sub-locality-d592fc58-02', NULL, 'single_choice', '下圖為某一定置漁場的要素組合圖，其成本支出主要是漁場工人的工資與購置漁具的支出。下列 敘述何者錯誤？ 網具 數量 擴張線 B A QQB B QA A B 漁場 工人', '["當漁場試圖由Q 的漁獲產量擴大捕撈時，其等成本線可能會由AA線向外移動 A", "擴張線上的各點皆以最低成本來生產", "漁場的長期平均成本線為水平線", "當漁場工人的工資成本增加時，會使漁場的等成本線平行移動 31860 50650"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:24+00:00", "source_pdf_sha1": "6852e28c95cc", "answer_pdf_sha1": "5696f1cd2c60", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "318", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "商業行政"}'::jsonb, NULL),
  ('locality-d592fc58-moex-00012', 'locality-d592fc58', 'locality-d592fc58-moex-114-d3ff7f6b', 'sub-locality-d592fc58-02', NULL, 'single_choice', '下列何種情況，資源配置符合生產效率？', '["生產組合落在生產可能線內", "生產組合落在生產可能線上", "生產組合落在生產可能線外", "改變資源配置可以增加所有商品的產出"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:24+00:00", "source_pdf_sha1": "6852e28c95cc", "answer_pdf_sha1": "5696f1cd2c60", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "318", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "商業行政"}'::jsonb, NULL),
  ('locality-d592fc58-moex-00013', 'locality-d592fc58', 'locality-d592fc58-moex-114-d3ff7f6b', 'sub-locality-d592fc58-02', NULL, 'single_choice', '下列何種特性會使市場產生自然獨占（naturalmonopoly）？', '["廠商獲得產品之獨家銷售權", "廠商在銷售其產品前必須得到政府的許可", "廠商擁有生產所需要原料之所有權", "技術特性讓一家廠商生產時的平均成本會低於兩家（含）以上生產時之平均成本"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:24+00:00", "source_pdf_sha1": "6852e28c95cc", "answer_pdf_sha1": "5696f1cd2c60", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "318", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "商業行政"}'::jsonb, NULL),
  ('locality-d592fc58-moex-00014', 'locality-d592fc58', 'locality-d592fc58-moex-114-d3ff7f6b', 'sub-locality-d592fc58-02', NULL, 'single_choice', '假設在一個有N家廠商的獨占性競爭市場裡，每家廠商所面對的需求為Q=80/N-P，總成本函 數為TC=0.5+Q2。當長期均衡達成時，N值為何？', '["20", "30", "40", "50"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:24+00:00", "source_pdf_sha1": "6852e28c95cc", "answer_pdf_sha1": "5696f1cd2c60", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "318", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "商業行政"}'::jsonb, NULL),
  ('locality-d592fc58-moex-00015', 'locality-d592fc58', 'locality-d592fc58-moex-114-d3ff7f6b', 'sub-locality-d592fc58-02', NULL, 'single_choice', '關於勞動供給的敘述，下列何者錯誤？', '["勞動供給曲線指的是勞動供給數量與薪資之間的關係", "勞動供給必定是一正斜率的曲線", "勞動供給曲線代表的是人們極大化效用的抉擇結果", "薪資上漲時，會產生替代與所得效果"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:24+00:00", "source_pdf_sha1": "6852e28c95cc", "answer_pdf_sha1": "5696f1cd2c60", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "318", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "商業行政"}'::jsonb, NULL),
  ('locality-d592fc58-moex-00016', 'locality-d592fc58', 'locality-d592fc58-moex-114-d3ff7f6b', 'sub-locality-d592fc58-02', NULL, 'single_choice', '推銷員小明的效用函數為U（I）= I，其中I為年所得。景氣好時每年可賺取100萬元，但景氣不佳時 只有36萬元的收入。假設景氣好壞的機率各半，則小明從事這份工作的風險貼水（riskpremium）為何？', '["10萬元", "8萬元", "6萬元", "4萬元"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:24+00:00", "source_pdf_sha1": "6852e28c95cc", "answer_pdf_sha1": "5696f1cd2c60", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "318", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "商業行政"}'::jsonb, NULL),
  ('locality-d592fc58-moex-00017', 'locality-d592fc58', 'locality-d592fc58-moex-114-d3ff7f6b', 'sub-locality-d592fc58-02', NULL, 'single_choice', '有關一般均衡分析與部分均衡分析的相異處，下列敘述何者正確？', '["前者考慮完全競爭下的情形；後者則否", "前者考慮所有商品及要素市場如何受價格機能調整至均衡；後者則否", "前者考慮長期均衡；後者則否", "前者考慮柏拉圖（Pareto）最適下的情形；後者則否"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:24+00:00", "source_pdf_sha1": "6852e28c95cc", "answer_pdf_sha1": "5696f1cd2c60", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "318", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "商業行政"}'::jsonb, NULL)
